const msg = $input.first().json;
return [{ json: {
  user_id: String(msg.message.from.id),
  chat_id: String(msg.message.chat.id),
  user_input: (msg.message.text || '').replace(/'/g, "''")
} }];

const rows = $input.all();
const history = rows.filter(r => r.json && r.json.text).map(r => `Usuario: ${r.json.text}${r.json.response ? '\nAsistente: ' + r.json.response : ''}`).join('\n');
return [{ json: {
  history: history || '(sin historial)',
  user_id: $('Extract Data').item.json.user_id,
  chat_id: $('Extract Data').item.json.chat_id,
  user_input: $('Extract Data').item.json.user_input
} }];

const raw = ($input.first().json.response || '').toLowerCase().trim();
const ctx = $('Prepare Context').item.json;
const txt = ctx.user_input.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

let intent = 'otro';
if (raw.includes('lead_propiedad') || raw.includes('lead')) intent = 'lead_propiedad';
else if (raw.includes('consulta_propiedad') || raw.includes('propiedad')) intent = 'consulta_propiedad';
else if (raw.includes('saludo')) intent = 'saludo';
else if (raw.includes('precio')) intent = 'precio';
else if (raw.includes('soporte')) intent = 'soporte';

if (intent === 'otro' && txt.match(/me interesa|quiero ver|mas info|visita|contacto|interesado/)) intent = 'lead_propiedad';
if (intent === 'otro' && txt.match(/casa|departamento|depto|arriendo|propiedad|vina|serena|santiago|valparaiso|nunoa|providencia|maipu/)) intent = 'consulta_propiedad';

return [{ json: { intent, user_id: ctx.user_id, chat_id: ctx.chat_id, user_input: ctx.user_input, history: ctx.history } }];

const rows = $input.all().map(i => i.json);
const existingLead = rows.find(r => r && r.id) || null;
const ctx = $('Parse Intent').item.json;
let intent = ctx.intent;
let lead_state = 'none';

if (existingLead) {
  if (!existingLead.nombre) {
    lead_state = 'needs_name';
    if (intent === 'otro') intent = 'lead_propiedad';
  } else if (!existingLead.telefono) {
    lead_state = 'needs_phone';
    if (intent === 'otro') intent = 'lead_propiedad';
  } else {
    lead_state = 'complete';
  }
} else if (intent === 'lead_propiedad') {
  lead_state = 'new';
}

return [{ json: { intent, lead_state, existing_lead: existingLead, user_id: ctx.user_id, chat_id: ctx.chat_id, user_input: ctx.user_input, history: ctx.history } }];

const ctx = $input.first().json;
const { lead_state, existing_lead, user_id, chat_id, user_input } = ctx;
const currentMsg = user_input.replace(/'/g, "''");
let reply, lead_sql;

if (lead_state === 'new') {
  reply = 'Perfecto 👌 ¿Me indicas tu nombre completo?';
  lead_sql = `INSERT INTO leads (user_id, interes) VALUES ('${user_id}', 'Propiedad consultada')`;
} else if (lead_state === 'needs_name') {
  reply = '¿Tu número de contacto? 📱';
  lead_sql = `UPDATE leads SET nombre = '${currentMsg}' WHERE id = ${existing_lead.id}`;
} else if (lead_state === 'needs_phone') {
  const nombre = existing_lead.nombre || 'Usuario';
  reply = `¡Gracias ${nombre}! Te contactaremos pronto 📞\\nNuestro equipo se pondrá en contacto a la brevedad.`;
  lead_sql = `UPDATE leads SET telefono = '${currentMsg}' WHERE id = ${existing_lead.id}`;
} else {
  reply = '¡Ya tenemos tus datos! Te contactaremos muy pronto 📞';
  lead_sql = 'SELECT 1';
}

return [{ json: { reply, reply_db: reply.replace(/'/g, "''"), user_id, chat_id, lead_sql } }];

return [{ json: {
  reply: $('Lead Handler').item.json.reply,
  reply_db: $('Lead Handler').item.json.reply_db,
  user_id: $('Lead Handler').item.json.user_id,
  chat_id: $('Lead Handler').item.json.chat_id
} }];

const ctx = $('Lead Resolver').item.json;
const state = $input.first().json;
const msg = ctx.user_input;
let next_step = null;
let reply = null;
let reply_markup = null;
let sql = null;

if (!state || !state.step) {
  next_step = 'comuna';
  reply = '¡Excelente! Iniciemos la búsqueda 🏡\\n\\n¿En qué *comuna* o sector buscas la propiedad?';
  sql = `INSERT INTO user_state (user_id, step) VALUES ('${ctx.user_id}', 'comuna') ON CONFLICT (user_id) DO UPDATE SET step = 'comuna'`;
} else if (state.step === 'comuna') {
  next_step = 'dormitorios';
  reply = `Perfecto, buscaremos en ${msg}. ¿Cuántos *dormitorios* necesitas?`;
  reply_markup = { keyboard: [[{text: '1'}, {text: '2'}], [{text: '3'}, {text: '4+'}], [{text: 'Cualquiera'}]], one_time_keyboard: true, resize_keyboard: true };
  sql = `UPDATE user_state SET step = 'dormitorios', comuna = '${msg}' WHERE user_id = '${ctx.user_id}'`;
} else if (state.step === 'dormitorios') {
  next_step = 'banos';
  reply = 'Entendido. ¿Y cuántos *baños* buscas?';
  reply_markup = { keyboard: [[{text: '1'}, {text: '2'}], [{text: '3+'}], [{text: 'Cualquiera'}]], one_time_keyboard: true, resize_keyboard: true };
  sql = `UPDATE user_state SET step = 'banos', dormitorios = '${msg}' WHERE user_id = '${ctx.user_id}'`;
} else if (state.step === 'banos') {
  next_step = 'done';
  reply = '¡Todo listo! Estoy buscando las mejores opciones para ti... ⏳';
  sql = `UPDATE user_state SET step = 'done', banos = '${msg}' WHERE user_id = '${ctx.user_id}'`;
}

return [{ json: { next_step, reply, reply_markup, sql, user_id: ctx.user_id, chat_id: ctx.chat_id, state } }];

const s = $('Wizard Logic').item.json.state;
const msg = $('Wizard Logic').item.json.reply; // Using current input which was the last step answer
const params = {
  comuna: s.comuna,
  dormitorios: parseInt(s.dormitorios) || 0,
  banos: parseInt($('Lead Resolver').item.json.user_input) || 0,
  sqm: 0
};
return [{ json: { params, user_id: s.user_id } }];

const props = $input.all().map(i => i.json).filter(p => p && p.id);
const ctx = $('Wizard Logic').item.json;
let reply;
if (props.length === 0) {
  reply = 'No encontré propiedades con esas características 😕\\n¿Te gustaría ajustar los filtros (menos dormitorios o cambiar la comuna)?';
} else {
  reply = '🏡 *Propiedades encontradas:*\\n\\n';
  props.forEach((p, i) => {
    const precio = p.price ? '$' + Number(p.price).toLocaleString('es-CL') : 'Consultar';
    reply += `${i+1}.\\n📍 *${p.title || 'Propiedad'}*\\n📍 Comuna: ${p.comuna || '-'}\\n💰 Precio: ${precio}\\n🛏 Dorm: ${p.bedrooms || p.dormitorios || '-'}\\n🛁 Baños: ${p.bathrooms || p.banos || '-'}\\n📐 M2: ${p.sqm || '-'}\\n\\n`;
  });
  reply += '¿Te interesa alguna para agendar visita? 👇';
}
return [{ json: { reply, reply_db: reply.replace(/'/g, "''"), user_id: ctx.user_id, chat_id: ctx.chat_id } }];

const ctx = $input.first().json;
const responses = { saludo: '¡Hola! 👋 ¿En qué puedo ayudarte hoy?', precio: '💰 Puedo ayudarte con precios. ¿Qué buscas?', soporte: '🛠 Cuéntame el problema y te ayudaré paso a paso.' };
const r = responses[ctx.intent] || '¿En qué puedo ayudarte?';
return [{ json: { reply: r, reply_db: r.replace(/'/g, "''"), user_id: ctx.user_id, chat_id: ctx.chat_id } }];

const rawReply = ($input.first().json.response || 'No pude generar una respuesta.').trim();
const ctx = $('Lead Resolver').item.json;
return [{ json: { reply: rawReply, reply_db: rawReply.replace(/'/g, "''"), user_id: ctx.user_id, chat_id: ctx.chat_id } }];

const chat_id = $('Extract Data').item.json.chat_id;
let reply = 'Procesado.';
let reply_markup = null;
const sources = ['Lead Reply', 'Format Property', 'Static Response', 'Format AI', 'Wizard Reply'];
for (const name of sources) {
  try {
    if ($(`${name}`).isExecuted) {
      const data = $(`${name}`).item.json;
      if (data.reply) { 
        reply = data.reply; 
        if (data.reply_markup) reply_markup = data.reply_markup;
        break; 
      }
    }
  } catch(e) {}
}
return [{ json: { chat_id, reply, reply_markup } }];
